function findWords(words) {
    const rows = [
        new Set("qwertyuiopQWERTYUIOP".split('')),
        new Set("asdfghjklASDFGHJKL".split('')),
        new Set("zxcvbnmZXCVBNM".split(''))
    ];
    const res = [];

    for (const word of words) {
        let row = -1;
        for (let i = 0; i < 3; i++) {
            if (rows[i].has(word[0])) {
                row = i;
                break;
            }
        }

        if (word.split('').every(c => rows[row].has(c))) {
            res.push(word);
        }
    }

    return res;
}
```


    1. Create an array of sets representing each row of the American keyboard. Include both uppercase and lowercase letters in the set.
2. Initialize an empty result list.
3. Loop through the input words array.
4. Determine the row of the first character of the current word by checking which of the 3 rows contains it.
5. Check if all the characters in the current word belong to the same row found in step 4. If yes, append the word to the result list.
6. Once the loop is done, return the result list.

solutionCode.java:
    ```java
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;

public class Solution {
    public String[] findWords(String[] words) {
        HashSet<Character>[] rows = new HashSet[] {
            new HashSet<Character>() {{
                add('q'); add('w'); add('e'); add('r'); add('t');
                add('y'); add('u'); add('i'); add('o'); add('p');
            }},
            new HashSet<Character>() {{
                add('a'); add('s'); add('d'); add('f'); add('g');
                add('h'); add('j'); add('k'); add('l');
            }},
            new HashSet<Character>() {{
                add('z'); add('x'); add('c'); add('v'); add('b');
                add('n'); add('m');
            }}
        };
        List<String> res = new ArrayList<>();

        for (String word : words) {
            int row = -1;
            for (int i = 0; i < 3; i++) {
                if (rows[i].contains(Character.toLowerCase(word.charAt(0)))) {
                    row = i;
                    break;
                }
            }

            boolean isOneRow = true;
            for (char letter : word.toCharArray()) {
                if (!rows[row].contains(Character.toLowerCase(letter))) {
                    isOneRow = false;
                    break;
                }
            }

            if (isOneRow)
                res.add(word);
        }

        return res.toArray(new String[0]);
    }
}
```


